from src.handlers import write_playbook

class Memory:
    def __init__(self):
        self.called = False
    def write_playbook(self, **payload):
        self.called = True
        return {'saved': 1, 'payload': payload}

def test_write_playbook_routes_through_memory_facade():
    memory = Memory()
    result = write_playbook(memory, {'name': 'Safe write'})
    assert memory.called is True
    assert result['saved'] == 1

